// Parse Google Sheets data into structured JSON
const response = $input.first().json;
const rows = response.values || [];

if (rows.length < 2) {
  throw new Error('No data found in sheet. Make sure you have headers and at least one row.');
}

// First row is headers
const headers = rows[0];
const dataRows = rows.slice(1);

// Convert to array of objects
const employees = dataRows.map(row => {
  const obj = {};
  headers.forEach((header, index) => {
    obj[header] = row[index] || '';
  });
  return obj;
});

// Filter out empty rows
const validEmployees = employees.filter(e => e.Name && e.Name.trim() !== '');

if (validEmployees.length === 0) {
  throw new Error('No valid employee data found.');
}

// Build Claude prompt
const dataStr = JSON.stringify(validEmployees, null, 2);

const systemPrompt = `You are a senior frontend developer specializing in React and Tailwind CSS.
Generate a beautiful, production-ready React TypeScript component from the provided data.
Rules:
- Output ONLY TSX code, no markdown fences, no explanations
- Use Tailwind CSS for all styling
- Make it responsive and visually appealing
- Use semantic HTML
- Export as: export const EmployeeDirectory = () => { ... }
- End with: export default EmployeeDirectory;`;

const userPrompt = `Create a beautiful Employee Directory React component using this data:

${dataStr}

Requirements:
- Show each employee as a card with avatar initials, name, role, email, department
- Use a clean grid layout (3 columns on desktop, 1 on mobile)
- Add department color badges
- Professional look with subtle shadows and hover effects
- Include a search/filter header`;

return [{
  json: {
    employees: validEmployees,
    totalCount: validEmployees.length,
    systemPrompt,
    userPrompt,
    componentName: 'EmployeeDirectory',
    filePath: 'src/components/generated/EmployeeDirectory.tsx',
    timestamp: new Date().toISOString()
  }
}];

// Parse Claude response and prepare for GitHub
const claudeResponse = $input.first().json;
const sheetData = $('Parse Sheet Data').first().json;

if (!claudeResponse.content || claudeResponse.content.length === 0) {
  throw new Error('Claude returned empty response.');
}

let generatedCode = claudeResponse.content[0].text || '';

// Strip markdown fences if any
generatedCode = generatedCode
  .replace(/^```[\w]*\n?/gm, '')
  .replace(/^```$/gm, '')
  .trim();

if (generatedCode.length < 100) {
  throw new Error('Generated code is too short.');
}

// Base64 encode for GitHub API
const encoded = Buffer.from(generatedCode, 'utf-8').toString('base64');

const commitMessage = `feat: auto-generate EmployeeDirectory from Google Sheets\n\nTotal employees: ${sheetData.totalCount}\nTimestamp: ${sheetData.timestamp}\n\n[skip ci]`;

return [{
  json: {
    ...sheetData,
    generatedCode,
    encoded,
    commitMessage,
    codePreview: generatedCode.slice(0, 200)
  }
}];

