const githubResult = $input.first().json;
const codeData = $('Parse Claude Response').first().json;

const commitUrl = githubResult.commit?.html_url ||
  `https://github.com/${process.env.GITHUB_OWNER}/${process.env.GITHUB_REPO}/blob/main/${codeData.filePath}`;

console.log('✅ Success!');
console.log('Component:', codeData.componentName);
console.log('Employees:', codeData.totalCount);
console.log('Commit:', commitUrl);

return [{
  json: {
    success: true,
    componentName: codeData.componentName,
    totalEmployees: codeData.totalCount,
    filePath: codeData.filePath,
    commitUrl,
    timestamp: codeData.timestamp
  }
}];
